patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index e1923a344179..799f9f0d9bd4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3489,6 +3489,7 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     return R;

   Value *X, *Y;
+  Value *C, *D;
   const APInt *CV;
   if (match(&I, m_c_Or(m_OneUse(m_Xor(m_Value(X), m_APInt(CV))), m_Value(Y))) &&
       !CV->isAllOnes() && MaskedValueIsZero(Y, *CV, 0, &I)) {
@@ -3506,14 +3507,48 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     return BinaryOperator::CreateMul(X, IncrementY);
   }

+  // (val / C) * D + (val % C) -> (val / C) * (D - C) + val
+  // This includes multiplication by a power of two (shl).
+  Value *Val;
+  const APInt *Divisor, *Multiplier;
+  auto matchMul = [&](Value *Mul, Value *Rem) -> bool {
+    return match(Rem, m_URem(m_Value(Val), m_APInt(Divisor))) &&
+           match(Mul, m_Mul(m_UDiv(m_Specific(Val), m_SpecificInt(*Divisor)), m_APInt(Multiplier)));
+  };
+  const APInt *Shift;
+  auto matchShl = [&](Value *Shl, Value *Rem) -> bool {
+    return match(Rem, m_URem(m_Value(Val), m_APInt(Divisor))) &&
+           match(Shl, m_Shl(m_UDiv(m_Specific(Val), m_SpecificInt(*Divisor)), m_APInt(Shift)));
+  };
+  if (cast<PossiblyDisjointInst>(&I)->isDisjoint()) {
+    LLVM_DEBUG(dbgs() << "visitOr: disjoint or\n");
+    if (matchMul(Op0, Op1) || matchMul(Op1, Op0)) {
+      LLVM_DEBUG(dbgs() << "visitOr: matched mul pattern\n");
+      APInt K = *Multiplier - *Divisor;
+      Value *Div = Builder.CreateUDiv(Val, ConstantInt::get(Ty, *Divisor));
+      Value *Mul = Builder.CreateMul(Div, ConstantInt::get(Ty, K));
+      Value *Add = Builder.CreateAdd(Mul, Val);
+      return replaceInstUsesWith(I, Add);
+    }
+    if (matchShl(Op0, Op1) || matchShl(Op1, Op0)) {
+      LLVM_DEBUG(dbgs() << "visitOr: matched shl pattern\n");
+      APInt DVal = APInt(Shift->getBitWidth(), 1) << *Shift;
+      APInt K = DVal - *Divisor;
+      Value *Div = Builder.CreateUDiv(Val, ConstantInt::get(Ty, *Divisor));
+      Value *Mul = Builder.CreateMul(Div, ConstantInt::get(Ty, K));
+      Value *Add = Builder.CreateAdd(Mul, Val);
+      return replaceInstUsesWith(I, Add);
+    }
+  }
+
   // (A & C) | (B & D)
-  Value *A, *B, *C, *D;
-  if (match(Op0, m_And(m_Value(A), m_Value(C))) &&
-      match(Op1, m_And(m_Value(B), m_Value(D)))) {
+  Value *A, *B, *MaskC, *MaskD;
+  if (match(Op0, m_And(m_Value(A), m_Value(MaskC))) &&
+      match(Op1, m_And(m_Value(B), m_Value(MaskD)))) {

     // (A & C0) | (B & C1)
     const APInt *C0, *C1;
-    if (match(C, m_APInt(C0)) && match(D, m_APInt(C1))) {
+    if (match(MaskC, m_APInt(C0)) && match(MaskD, m_APInt(C1))) {
       Value *X;
       if (*C0 == ~*C1) {
         // ((X | B) & MaskC) | (B & ~MaskC) -> (X & MaskC) | B
@@ -3564,48 +3599,48 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     // 'or' that it is replacing.
     if (Op0->hasOneUse() || Op1->hasOneUse()) {
       // (Cond & C) | (~Cond & D) -> Cond ? C : D, and commuted variants.
-      if (Value *V = matchSelectFromAndOr(A, C, B, D))
+      if (Value *V = matchSelectFromAndOr(A, MaskC, B, MaskD))
         return replaceInstUsesWith(I, V);
-      if (Value *V = matchSelectFromAndOr(A, C, D, B))
+      if (Value *V = matchSelectFromAndOr(A, MaskC, MaskD, B))
         return replaceInstUsesWith(I, V);
-      if (Value *V = matchSelectFromAndOr(C, A, B, D))
+      if (Value *V = matchSelectFromAndOr(MaskC, A, B, MaskD))
         return replaceInstUsesWith(I, V);
-      if (Value *V = matchSelectFromAndOr(C, A, D, B))
+      if (Value *V = matchSelectFromAndOr(MaskC, A, MaskD, B))
         return replaceInstUsesWith(I, V);
-      if (Value *V = matchSelectFromAndOr(B, D, A, C))
+      if (Value *V = matchSelectFromAndOr(B, MaskD, A, MaskC))
         return replaceInstUsesWith(I, V);
-      if (Value *V = matchSelectFromAndOr(B, D, C, A))
+      if (Value *V = matchSelectFromAndOr(B, MaskD, MaskC, A))
         return replaceInstUsesWith(I, V);
-      if (Value *V = matchSelectFromAndOr(D, B, A, C))
+      if (Value *V = matchSelectFromAndOr(MaskD, B, A, MaskC))
         return replaceInstUsesWith(I, V);
-      if (Value *V = matchSelectFromAndOr(D, B, C, A))
+      if (Value *V = matchSelectFromAndOr(MaskD, B, MaskC, A))
         return replaceInstUsesWith(I, V);
     }
   }
-
-  if (match(Op0, m_And(m_Value(A), m_Value(C))) &&
-      match(Op1, m_Not(m_Or(m_Value(B), m_Value(D)))) &&
+  Value *AndMask, *OrMask;
+  if (match(Op0, m_And(m_Value(A), m_Value(AndMask))) &&
+      match(Op1, m_Not(m_Or(m_Value(B), m_Value(OrMask)))) &&
       (Op0->hasOneUse() || Op1->hasOneUse())) {
     // (Cond & C) | ~(Cond | D) -> Cond ? C : ~D
-    if (Value *V = matchSelectFromAndOr(A, C, B, D, true))
+    if (Value *V = matchSelectFromAndOr(A, AndMask, B, OrMask, true))
       return replaceInstUsesWith(I, V);
-    if (Value *V = matchSelectFromAndOr(A, C, D, B, true))
+    if (Value *V = matchSelectFromAndOr(A, AndMask, OrMask, B, true))
       return replaceInstUsesWith(I, V);
-    if (Value *V = matchSelectFromAndOr(C, A, B, D, true))
+    if (Value *V = matchSelectFromAndOr(AndMask, A, B, OrMask, true))
       return replaceInstUsesWith(I, V);
-    if (Value *V = matchSelectFromAndOr(C, A, D, B, true))
+    if (Value *V = matchSelectFromAndOr(AndMask, A, OrMask, B, true))
       return replaceInstUsesWith(I, V);
   }
-
+  Value *XorC;
   // (A ^ B) | ((B ^ C) ^ A) -> (A ^ B) | C
   if (match(Op0, m_Xor(m_Value(A), m_Value(B))))
-    if (match(Op1, m_Xor(m_Xor(m_Specific(B), m_Value(C)), m_Specific(A))))
-      return BinaryOperator::CreateOr(Op0, C);
+    if (match(Op1, m_Xor(m_Xor(m_Specific(B), m_Value(XorC)), m_Specific(A))))
+      return BinaryOperator::CreateOr(Op0, XorC);

   // ((A ^ C) ^ B) | (B ^ A) -> (B ^ A) | C
-  if (match(Op0, m_Xor(m_Xor(m_Value(A), m_Value(C)), m_Value(B))))
+  if (match(Op0, m_Xor(m_Xor(m_Value(A), m_Value(XorC)), m_Value(B))))
     if (match(Op1, m_Xor(m_Specific(B), m_Specific(A))))
-      return BinaryOperator::CreateOr(Op1, C);
+      return BinaryOperator::CreateOr(Op1, XorC);

   if (Instruction *DeMorgan = matchDeMorgansLaws(I, *this))
     return DeMorgan;

log.expect_optimized_program:
define i32 @fold_add_udiv_urem_to_mul(i32 noundef %val) {
entry:
  %add = mul i32 %val, 3
  ret i32 %add
}
